const fileURL = $('seta_dados_entrada').item.json.fileURL;

const requestBody = {
  model: "gpt-4o",
  messages: [
    {
      role: "system",
      content: "Voce e um extrator de dados de comprovantes financeiros (PIX, TED, DOC, transferencias, pagamentos). Analise o documento e extraia as informacoes. Responda APENAS com JSON valido, sem markdown, sem explicacoes."
    },
    {
      role: "user",
      content: [
        {
          type: "image_url",
          image_url: { url: fileURL }
        },
        {
          type: "text",
          text: "Extraia do comprovante:\n{\n  \"data_transacao\": \"dd/MM/yyyy\",\n  \"transacao\": \"descricao curta (ex: PIX recebido de Fulano, Transferencia para Empresa X)\",\n  \"categoria\": \"entrada ou saida (se o titular RECEBEU = entrada, se PAGOU/ENVIOU = saida)\",\n  \"valor\": 0.00\n}\nValor = apenas numero, sem R$. Se nao encontrar data, use null."
        }
      ]
    }
  ],
  max_tokens: 500
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const fileId = $input.first().json.id;

const requestBody = {
  model: "gpt-4o",
  input: [
    {
      role: "system",
      content: "Voce e um extrator de dados de comprovantes financeiros (PIX, TED, DOC, transferencias, pagamentos). Analise o documento e extraia as informacoes. Responda APENAS com JSON valido, sem markdown, sem explicacoes."
    },
    {
      role: "user",
      content: [
        {
          type: "input_file",
          file_id: fileId
        },
        {
          type: "input_text",
          text: "Extraia do comprovante:\n{\n  \"data_transacao\": \"dd/MM/yyyy\",\n  \"transacao\": \"descricao curta (ex: PIX recebido de Fulano, Transferencia para Empresa X)\",\n  \"categoria\": \"entrada ou saida (se o titular RECEBEU = entrada, se PAGOU/ENVIOU = saida)\",\n  \"valor\": 0.00\n}\nValor = apenas numero, sem R$. Se nao encontrar data, use null."
        }
      ]
    }
  ]
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const raw = $input.first().json;
let content = '';

try {
  content = raw.choices[0].message.content;
} catch (e1) {
  try {
    const msgBlock = raw.output.find(o => o.type === 'message');
    const textBlock = msgBlock.content.find(c => c.type === 'output_text');
    content = textBlock.text;
  } catch (e2) {
    throw new Error('Resposta Vision invalida: ' + JSON.stringify(raw).substring(0, 500));
  }
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('JSON invalido: ' + content);
}

const categoria = (parsed.categoria || '').toLowerCase().trim();
const isEntrada = categoria.includes('entrada');
const valor = parseFloat(parsed.valor) || 0;

return [{
  json: {
    data_transacao: parsed.data_transacao || new Date().toLocaleDateString('pt-BR'),
    transacao: parsed.transacao || 'Comprovante financeiro',
    categoria: isEntrada ? 'entrada' : 'saída',
    entrada: isEntrada ? valor : 0,
    saida: isEntrada ? 0 : valor
  }
}];

